mapper.select:
	/* com.erns.es.code.mapper.CodeMasterDAO.getList */

	SELECT B.* FROM (
		SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() TOTAL FROM (
			SELECT

			FROM T_CODE_MST AA



			ORDER BY AA.GRP_CODE
		) A
	) B

    	WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

/* com.erns.es.code.mapper.CodeMasterDAO.load */

SELECT

FROM T_CODE_MST AA


	AA.GRP_CODE = #{grpCode, jdbcType=VARCHAR}

mapper.insert:
/* com.erns.es.code.mapper.CodeMasterDAO.insert */

INSERT INTO T_CODE_MST (
		GRP_CODE
	, GRP_CODE_NAME
	, CODE_DESC
	, ETC_CMMT
	, USE_YN
	, DEL_YN

	, RGTR
	, RGT_DTTM
	, CHNR
	, CHNG_DTTM
) VALUES (
		#{grpCode			, jdbcType=VARCHAR}
	, #{grpCodeName	, jdbcType=VARCHAR}
	, #{codeDesc		, jdbcType=VARCHAR}
	, #{etcCmmt			, jdbcType=VARCHAR}
	, COALESCE(#{useYn		, jdbcType=CHAR}, 'Y')
	, COALESCE(#{delYn		, jdbcType=CHAR}, 'N')

	, #{rgtr		, jdbcType=INTEGER}
	, now()
	, #{chnr		, jdbcType=INTEGER}
	, now()
)

mapper.update:
/* com.erns.es.code.mapper.CodeMasterDAO.update */

UPDATE T_CODE_MST SET
		GRP_CODE_NAME  = 	#{grpCodeName	, jdbcType=VARCHAR}
	, CODE_DESC			 = 	#{codeDesc		, jdbcType=VARCHAR}
	, ETC_CMMT			 = 	#{etcCmmt			, jdbcType=VARCHAR}

	, CHNR					=  #{chnr			, jdbcType=INTEGER}
	, CHNG_DTTM		 	=  now()

	GRP_CODE = #{grpCode, jdbcType=VARCHAR}

/* com.erns.es.code.mapper.CodeMasterDAO.updateUseYn */

UPDATE T_CODE_MST SET
		USE_YN        = COALESCE(#{useYn		, jdbcType=CHAR}, 'Y')

	, CHNR					= #{chnr			, jdbcType=INTEGER}
	, CHNG_DTTM		 	= now()

	GRP_CODE 				= #{grpCode, jdbcType=VARCHAR}

/* com.erns.es.code.mapper.CodeMasterDAO.updateDelYn */

UPDATE T_CODE_MST SET
		DEL_YN        = COALESCE(#{delYn		, jdbcType=CHAR}, 'Y')

	, CHNR					= #{chnr			, jdbcType=INTEGER}
	, CHNG_DTTM		 	= now()

	GRP_CODE 				= #{grpCode, jdbcType=VARCHAR}

mapper.delete:
/* com.erns.es.code.mapper.CodeMasterDAO.delete */

DELETE FROM T_CODE_MST

	AND GRP_CODE = #{grpCode, jdbcType=VARCHAR}
